public class TernVsIf {
    public static void main(String[] args) {
        int age = 20;
        // Ternary (good for simple 2-way)
        String status1 = (age >= 18) ? "Adult" : "Minor";
        System.out.println("Ternary: " + status1);
        // If/else (same result)
        String status2;
        if (age >= 18) { status2 = "Adult"; }
        else { status2 = "Minor"; }
        System.out.println("If/else: " + status2);
        // If/else (better for complex)
        if (age >= 65) { System.out.println("Senior discount"); }
        else if (age >= 18) { System.out.println("Full price"); }
        else { System.out.println("Child discount"); }
    }
}

public class BooleanZen {
    public static void main(String[] args) {
        boolean active = true;
        int count = 5;
        // Verbose (bad)
        if (active == true) { System.out.println("V1: active"); }
        if (count > 0 == true) { System.out.println("V2: has items"); }
        // Clean (Boolean Zen)
        if (active) { System.out.println("Z1: active"); }
        if (count > 0) { System.out.println("Z2: has items"); }
        // Return simplification
        System.out.println("Even: " + isEven(4));
    }
    // Bad: if(n%2==0) return true; else return false;
    static boolean isEven(int n) { return n % 2 == 0; }
}

