public class Shipping {
    public static void main(String[] args) {
        double weight = 3.5; String dest = "EU"; boolean express = true;
        double cost;
        if (weight <= 0) { cost = 0; System.out.println("Invalid weight"); }
        else if (dest.equals("UK")) {
            cost = weight <= 1 ? 3.99 : weight <= 5 ? 5.99 : 9.99;
            if (express) cost *= 1.5;
        } else if (dest.equals("EU")) {
            cost = weight <= 1 ? 7.99 : weight <= 5 ? 12.99 : 24.99;
            if (express) cost *= 1.8;
        } else {
            cost = weight <= 1 ? 14.99 : weight <= 5 ? 24.99 : 49.99;
            if (express) cost *= 2.0;
        }
        System.out.printf("%.1fkg to %s%s: %.2f%n", weight, dest, express?" (EXPRESS)":"", cost);
    }
}

